create table dirkspzm32.tms_loading_points (
    sid                  varchar2(2 char) not null enable,
    firma_nr             number(6, 0) not null enable,
    lgr_platz            varchar2(30 char) not null enable,
    order_vorgang_id     number(*, 0),
    vehicle_number_plate varchar2(30 char),
    arrival_time         date,
    loading_start_time   date,
    departure_time       date,
    driver_name          varchar2(255 char),
    loading_temp_cent    number(*, 5),
    vehicle_temp_cent    number(*, 5),
    address_id_carrier   number(*, 0),
    status               varchar2(10 char) default 'FR' not null enable,
    last_change_date     date not null enable,
    last_change_login_id number(*, 0) default - 1 not null enable,
    info                 varchar2(255 char),
    arbeitsplatz_id      number(*, 0)
);

alter table dirkspzm32.tms_loading_points
    add constraint pk_tms_loading_points
        primary key ( lgr_platz,
                      firma_nr,
                      sid )
            using index enable;


